def mse_reconstruction_loss(x_recon, x_target):
    """
    MSE reconstruction loss — Gaussian decoder with unit variance.
    x_recon:  decoder output, shape (B, D)
    x_target: continuous target, shape (B, D)
    Returns: scalar (mean over batch and dims)
    """
    return F.mse_loss(x_recon, x_target, reduction='mean')

# Note: with fixed σ²=1, MSE is proportional to -log N(x; recon, I).
# If σ² is learned or set differently, scale the MSE accordingly:
def gaussian_nll(x_recon, x_target, log_var=0.0):
    """Exact Gaussian NLL with per-element log variance."""
    return 0.5 * (log_var + (x_target - x_recon).pow(2) / log_var.exp()).mean()
